import React, { useState } from 'react';
import { format, addDays, subDays, differenceInDays, startOfDay, eachMonthOfInterval, isToday, startOfMonth, endOfMonth } from 'date-fns';
import { ru } from 'date-fns/locale';
import './GanttChart.css';

const PERIOD_DAYS = 365;

function GanttChart({ tasks, onTaskClick, members }) {
  const today = startOfDay(new Date());
  const [viewStart, setViewStart] = useState(subDays(today, 30));
  const [filterAssignee, setFilterAssignee] = useState('all');

  const viewEnd = addDays(viewStart, PERIOD_DAYS - 1);

  const goBack = () => setViewStart(prev => subDays(prev, 30));
  const goForward = () => setViewStart(prev => addDays(prev, 30));
  const goToday = () => setViewStart(subDays(today, 30));

  const tasksWithDates = tasks
    .filter(t => t.start_date && t.end_date)
    .filter(t => {
      if (filterAssignee === 'all') return true;
      return t.assignees && t.assignees.some(a => a.id === parseInt(filterAssignee));
    });

  // Позиция задачи в процентах от общей ширины
  const getPct = (date) => {
    const d = startOfDay(new Date(date));
    const offset = differenceInDays(d, viewStart);
    return (offset / PERIOD_DAYS) * 100;
  };

  const getTaskPosition = (task) => {
    const leftPct = getPct(task.start_date);
    const rightPct = getPct(task.end_date) + (1 / PERIOD_DAYS * 100);
    const clampedLeft = Math.max(0, leftPct);
    const clampedRight = Math.min(100, rightPct);
    const width = clampedRight - clampedLeft;
    const isOutOfView = rightPct < 0 || leftPct > 100;
    return { left: `${clampedLeft}%`, width: `${Math.max(0.3, width)}%`, isOutOfView };
  };

  const isTaskDone = (task) => {
    const s = (task.status_name || '').toLowerCase();
    return s === 'готово' || s === 'done' || s === 'выполнено';
  };

  const getTaskColor = (task) => {
    if (isTaskDone(task)) return '#66bb6a';
    if (task.has_report) return '#26a69a';
    if (task.end_date && new Date(task.end_date) < today) return '#ef5350';
    return '#42a5f5';
  };

  // Месяцы для шапки и вертикальных линий
  const months = eachMonthOfInterval({ start: viewStart, end: viewEnd });

  const todayPct = (differenceInDays(today, viewStart) / PERIOD_DAYS) * 100;
  const showTodayLine = todayPct >= 0 && todayPct <= 100;

  if (tasks.filter(t => t.start_date && t.end_date).length === 0) {
    return (
      <div className="gantt-empty">
        <p>Нет задач с установленными датами</p>
        <p>Добавьте даты начала и окончания к задачам, чтобы увидеть диаграмму Ганта</p>
      </div>
    );
  }

  return (
    <div className="gantt-container">
      {/* Панель управления */}
      <div className="gantt-controls">
        <div className="gantt-nav">
          <button className="gantt-nav-btn" onClick={goBack}>◀</button>
          <button className="gantt-nav-btn gantt-today-btn" onClick={goToday}>Сегодня</button>
          <button className="gantt-nav-btn" onClick={goForward}>▶</button>
          <span className="gantt-period-label">
            {format(viewStart, 'd MMM yyyy', { locale: ru })} — {format(viewEnd, 'd MMM yyyy', { locale: ru })}
          </span>
        </div>

        <div className="gantt-filter">
          <select className="gantt-assignee-filter" value={filterAssignee} onChange={e => setFilterAssignee(e.target.value)}>
            <option value="all">Все исполнители</option>
            {members && members.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
          </select>
        </div>

        <div className="gantt-legend">
          <div className="legend-item"><span className="legend-color" style={{ background: '#42a5f5' }}></span><span>В процессе</span></div>
          <div className="legend-item"><span className="legend-color" style={{ background: '#66bb6a' }}></span><span>Выполнено</span></div>
          <div className="legend-item"><span className="legend-color" style={{ background: '#26a69a' }}></span><span>Отчёт сдан</span></div>
          <div className="legend-item"><span className="legend-color" style={{ background: '#ef5350' }}></span><span>Просрочена</span></div>
        </div>
      </div>

      {/* Таблица */}
      <div className="gantt-chart">
        {/* Шапка с месяцами */}
        <div className="gantt-header">
          <div className="gantt-sidebar-header">Задача</div>
          <div className="gantt-timeline-header">
            {months.map((monthStart, i) => {
              const mStart = monthStart < viewStart ? viewStart : monthStart;
              const mEnd = endOfMonth(monthStart) > viewEnd ? viewEnd : endOfMonth(monthStart);
              const leftPct = (differenceInDays(mStart, viewStart) / PERIOD_DAYS) * 100;
              const widthPct = ((differenceInDays(mEnd, mStart) + 1) / PERIOD_DAYS) * 100;
              return (
                <div key={i} className="gantt-month-header" style={{ left: `${leftPct}%`, width: `${widthPct}%` }}>
                  {format(monthStart, 'LLL yyyy', { locale: ru })}
                </div>
              );
            })}
          </div>
        </div>

        {/* Строки задач */}
        <div className="gantt-body">
          {tasksWithDates.length === 0 ? (
            <div style={{ padding: '40px', color: '#aaa', textAlign: 'center' }}>
              Нет задач для выбранного исполнителя
            </div>
          ) : tasksWithDates.map(task => {
            const pos = getTaskPosition(task);
            return (
              <div key={task.id} className="gantt-row">
                {/* Название задачи */}
                <div className="gantt-sidebar">
                  <div className="gantt-task-info">
                    <div className="gantt-task-title">{task.title}</div>
                    {task.assignees && task.assignees.length > 0 && (
                      <div className="gantt-task-assignees">
                        {task.assignees.map(a => (
                          <span key={a.id} className="gantt-assignee-badge" title={a.name}>
                            {a.name.charAt(0)}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                </div>

                {/* Таймлайн строки */}
                <div className="gantt-timeline">
                  {/* Вертикальные линии месяцев */}
                  {months.map((m, i) => {
                    const pct = (differenceInDays(m < viewStart ? viewStart : m, viewStart) / PERIOD_DAYS) * 100;
                    return <div key={i} className="gantt-month-line" style={{ left: `${pct}%` }} />;
                  })}

                  {/* Линия сегодня */}
                  {showTodayLine && <div className="gantt-today-line" style={{ left: `${todayPct}%` }} />}

                  {/* Полоса задачи */}
                  {!pos.isOutOfView && (
                    <div
                      className="gantt-task-bar"
                      style={{ left: pos.left, width: pos.width, background: getTaskColor(task) }}
                      onClick={() => onTaskClick(task)}
                      title={`${task.title}\n${format(new Date(task.start_date), 'dd.MM.yyyy')} – ${format(new Date(task.end_date), 'dd.MM.yyyy')}`}
                    >
                      <span className="gantt-task-bar-label">{task.title}</span>
                    </div>
                  )}

                  {/* Если вне периода */}
                  {pos.isOutOfView && (
                    <div className="gantt-out-of-view">← вне периода →</div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

export default GanttChart;
